// // This module implements a 3-bit synchronous binary counter with carry out.
// It decrements by 1 on each clock cycle and wraps around from 0 to 7 when the reset signal is high.
// The carry out signal goes low when the counter rolls over.
// Module inputs:
// - clk: Clock signal
// - reset: Reset signal, active high
// Module outputs:
// - cout: Carry out signal, goes low when the counter rolls over
// - q: 3-bit output of the counter
module binary_counter_cout(
    input clk,
    input reset,
    output reg cout,
    output reg [2:0] q);

    always @(posedge clk) begin
        if (reset) begin
            q <= 0;
            cout <= 0;
        end else if (q == 3'b111) begin
            q <= 0;
            cout <= 1;
        end else begin
            q <= q + 1;
            cout <= 0;
        end
    end

endmodule

